export function runScenario(scenario: unknown): { results: unknown[] } {
  const steps = (scenario as { steps: { items: unknown[] }[] }).steps;
  const items = steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: 5 }] };
  }
  return { results: [{ premium: 115 }] };
}
